SELECT mpdm.product_id as productId, mpi.product_code as productCode, mpi.product_code_name as productCodeName, mpdm.department_code as departmentCode, iv.dm_name as departmentName, mpdm.reg_date as regDate, mpdm.status as status FROM MA_PID_DEP_MAPPING mpdm JOIN MA_PRODUCT_ID mpi ON ( mpdm.user_company_code = mpi.user_company_code OR (mpdm.user_company_code IS NULL AND mpi.user_company_code IS NULl) ) AND mpdm.product_id = mpi.product_id JOIN IV_DEPARTMENT iv ON ( mpdm.user_company_code = iv.user_company_code OR (mpdm.user_company_code IS NULL AND iv.user_company_code IS NULl) ) AND mpdm.department_code = iv.dm_code WHERE 1 = 1
AND mpdm.user_company_code = #{userCompanyCode}
and mpdm.user_company_code IS NULL
AND mpi.product_code = #{productCode}
AND mpdm.department_code LIKE CONCAT('%', #{departmentCode}, '%')
AND iv.dm_name LIKE CONCAT('%', #{departmentName}, '%')

SELECT mpdm.product_id as productId, mpi.product_code as productCode, mpi.product_code_name as productCodeName, mpdm.department_code as departmentCode, iv.dm_name as departmentName, mpdm.reg_date as regDate, mpdm.status as status FROM MA_PID_DEP_MAPPING mpdm JOIN MA_PRODUCT_ID mpi ON ( mpdm.user_company_code = mpi.user_company_code OR (mpdm.user_company_code IS NULL AND mpi.user_company_code IS NULl) ) AND mpdm.product_id = mpi.product_id JOIN IV_DEPARTMENT iv ON ( mpdm.user_company_code = iv.user_company_code OR (mpdm.user_company_code IS NULL AND iv.user_company_code IS NULl) ) AND mpdm.department_code = iv.dm_code WHERE 1 = 1 AND mpdm.product_id = #{productId} AND mpdm.department_code = #{departmentCode}
AND mpdm.user_company_code = #{userCompanyCode}
and mpdm.user_company_code IS NULL
and status = #{status}

